#include <bits/stdc++.h>
using namespace std;
#define int long long
const int maxn=5e5+5;
int n,a[maxn],ans=-1,cnt;
signed main(){
	ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);
	cin>>n;
	for(int i=1;i<=n;i++){
		cin>>a[i];
		ans=max(a[i],ans);
	}
    sort(a+1,a+n+1);
	a[n]=-1;
    sort(a+1,a+n+1);
	for(int i=2;i<n;i++){
		if(a[i]-a[i-1]>1){
			cout<<ans*(a[i-1]+1);
			return 0;
		}
	}
	cout<<ans*(a[n]+1);
	return 0;
}
